module RefModule (  
    input clk,  
    input rst,  
    input [7:0] data_in,  
    input read,  
    input write,  
    input erase,  
    output reg [7:0] data_out  
);  

    reg [7:0] unused_memory;  

    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            unused_memory <= 8'b0;  
            data_out <= 8'b0;  
        end else begin  
            if (erase) begin  
                unused_memory <= 8'b0;  
            end else if (write) begin  
                unused_memory <= data_in;  
            end else if (read) begin  
                data_out <= unused_memory;  
            end  
        end  
    end  
endmodule
